function maxIncreaseKeepingSkyline(grid) {
    const n = grid.length;
    const row_max = new Array(n).fill(0);
    const col_max = new Array(n).fill(0);

    for (let i = 0; i < n; ++i) {
        for (let j = 0; j < n; ++j) {
            row_max[i] = Math.max(row_max[i], grid[i][j]);
            col_max[j] = Math.max(col_max[j], grid[i][j]);
        }
    }

    let total_sum = 0;
    for (let i = 0; i < n; ++i) {
        for (let j = 0; j < n; ++j) {
            total_sum += Math.min(row_max[i], col_max[j]) - grid[i][j];
        }
    }

    return total_sum;
}
```


    1. Find the maximum height of the buildings in each row and store them in 'row_max'.
2. Find the maximum height of the buildings in each column and store them in 'col_max'.
3. Iterate through each building in the grid and calculate the minimum of the row_max and col_max for the current building.
4. Subtract the current building height from the minimum value found in step 3 and add the result to the total_sum.
5. Return the total_sum.

